  ('locality-6f0ba476-moex-00575', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列有關遺產稅之課徵範圍，何者錯誤？', '["死亡事實或贈與行為發生前2年內，被繼承人自願喪失中華民國國籍者，仍應依遺產及贈 與稅法課徵遺產稅", "經常居住中華民國境外之國民，應就其在中華民國境內之財產，課徵遺產稅", "信託關係存續中受益人死亡時，應就其享有信託利益之權利已領受部分，課徵遺產稅", "因遺囑成立之信託，於遺囑人死亡時，其信託財產應依遺產及贈與稅法規定，課徵遺產稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00576', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列何者情況不計入贈與總額課稅？', '["贈與人為子女所支付之生活費、教育費及醫藥費", "贈與人與其弟弟間財產之買賣且弟弟無法提出所支付價款之確實證明", "贈與人以自己的資金，無償為妹妹購置不動產", "贈與人以顯著不相當代價，讓與股票給其姐姐"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00577', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列那些屬於遺產及贈與稅法規定，每遇消費者物價指數較上次調整之指數累計上漲達10%', '["免稅額", "課稅級距金額", "被繼承人日常生活必需之 器具及用具、職業上之工具，不計入遺產總額之金額", "父母於子女婚嫁時所贈與之財物不 計入贈與總額之金額  ⑤被繼承人之喪葬費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00578', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '甲君110年7月2日出售其110年1月3日取得的房地，出售價格為1,000萬元，取得成本 為600萬元，出售時之公告土地現值為400萬元，申報土地現值為800萬元，前次移轉現值 為400萬元；假設無其他費用，該出售土地符合土地增值稅之自用住宅用地，稅率10%，不 符合自住房屋土地減免所得稅規定，請計算該房地交易所得稅額。', '["0元", "162萬元", "180萬元", "202萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00579', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '土地所有權人因重購土地退還土地增值稅者，其重購之土地，自完成移轉登記之日起，於幾 年內再行移轉或改作其他用途時，除就該次移轉之漲價總數課徵土地增值稅外，並應追繳原 退還稅款？', '["1年", "2年", "5年", "7年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00580', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列有關土地增值稅徵免之敘述，何者錯誤？', '["甲贈與土地給兒子，納稅義務人不能主張適用自用住宅用地稅率核課土地增值稅", "乙贈與土地給配偶，得申請不課徵土地增值稅", "丙有一塊作農業使用之農地，打算賣給公務員退休的好友，得申請不課徵土地增值稅", "丁出售一筆非都市計畫法劃定之「道路用地」，享有免徵土地增值稅優惠"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00581', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '某甲於 108 年 9 月 1 日出售自用住宅，申報土地移轉現值 1,750,000 元，課徵土地增值稅 400,000元，嗣於110年8月15日訂約購置自用住宅，同年9月5日申報移轉重購自用住宅， 土地移轉現值1,800,000元，請問某甲申請重購退稅金額為何？', '["不符合重購退稅規定", "50,000元", "400,000元", "450,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00582', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列有關房屋稅課徵之說明，何者錯誤？', '["房屋頂樓增建廣告塔，除加重其房屋負荷外，未增加房屋使用價值，不課徵房屋稅", "電梯為附著於房屋之設備，且增加房屋之使用價值，應併計房屋現值課徵房屋稅", "空置房屋應按非自住之住家用稅率課徵房屋稅", "違章建築房屋應依實際使用情形，依法課徵房屋稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00583', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列有關房屋標準價格之評定與公告，何者敘述錯誤？', '["房屋標準價格，由不動產評價委員會評定，按各種建造材料所建房屋，區分種類及等級", "房屋標準價格，每3年重新評定一次，並應依其耐用年數予以折舊，按年遞減其價格", "房屋標準價格，由不動產評價委員會評定，並由財政部公告之", "房屋標準價格，由不動產評價委員會評定，按各類房屋之耐用年數及折舊標準評定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00584', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-d3ff7f6b', 'sub-locality-6f0ba476-06', NULL, 'essay', '請作圖並佐以文字說明你是否同意下列敘述：「如果政府課稅不會造成
